/**
 * PIR crypto client - handles all local cryptographic operations
 */
public protocol PirCryptoClientProtocol : AnyObject {
    
    /**
     * Decrypt PIR response from lightwalletd
     *
     * Takes the response bytes from gRPC InspireQuery() and returns SpentInfo if found
     */
    func decryptResponse(responseBytes: Data, nullifierHex: String) throws  -> FfiSpentInfo?
    
    /**
     * Generate encrypted PIR query for a nullifier
     *
     * Returns query bytes to send to lightwalletd via gRPC InspireQuery()
     */
    func generateQuery(nullifierHex: String) throws  -> FfiPirQuery
    
    /**
     * Get Cuckoo bucket indices for a nullifier
     */
    func getBucketIndices(nullifierHex: String) throws  -> [UInt64]
    
    /**
     * Get the protocol name
     */
    func getProtocol()  -> String
    
    /**
     * Initialize with parameters from lightwalletd GetPirParams response
     */
    func initialize(params: FfiPirParams) throws 
    
    /**
     * Check if keys have been precomputed
     */
    func keysReady()  -> Bool
    
    /**
     * Precompute cryptographic keys (expensive, ~3s for InsPIRe)
     */
    func precomputeKeys() throws 
    
}

