 * PIR parameters received from lightwalletd
 */
public struct FfiPirParams {
    /**
     * The highest block covered by the PIR database
     */
    public var pirCutoffHeight: UInt64
    /**
     * Protocol name: "inspire" or "ypir"
     */
    public var `protocol`: String
    /**
     * Full parameters as JSON (from lightwalletd GetPirParams response)
     */
    public var paramsJson: String

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(
        /**
         * The highest block covered by the PIR database
         */pirCutoffHeight: UInt64, 
        /**
         * Protocol name: "inspire" or "ypir"
         */`protocol`: String, 
        /**
         * Full parameters as JSON (from lightwalletd GetPirParams response)
         */paramsJson: String) {
        self.pirCutoffHeight = pirCutoffHeight
        self.`protocol` = `protocol`
        self.paramsJson = paramsJson
    }
}



extension FfiPirParams: Equatable, Hashable {
    public static func ==(lhs: FfiPirParams, rhs: FfiPirParams) -> Bool {
        if lhs.pirCutoffHeight != rhs.pirCutoffHeight {
            return false
        }
        if lhs.`protocol` != rhs.`protocol` {
            return false
        }
        if lhs.paramsJson != rhs.paramsJson {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(pirCutoffHeight)
        hasher.combine(`protocol`)
        hasher.combine(paramsJson)
    }
}


